async function handleReadToolCall(name, args, bridge) {
  switch (name) {
    case "getBasicInfo": {
      const info = await bridge.call("getBasicInfo");
      if (!info) {
        throw new Error("Editor not ready. Ensure a file is open in Paper.");
      }
      return { content: [{ type: "text", text: JSON.stringify(info, null, 2) }] };
    }
    case "getSelection": {
      const selection = await bridge.call("getSelection");
      if (!selection) {
        throw new Error("Editor not ready. Ensure a file is open in Paper.");
      }
      return { content: [{ type: "text", text: JSON.stringify(selection, null, 2) }] };
    }
    case "getNodeInfo": {
      const nodeId = args["nodeId"];
      const info = await bridge.call("getNodeInfo", nodeId);
      if (!info) {
        throw new Error(`Node not found: ${nodeId}`);
      }
      return { content: [{ type: "text", text: JSON.stringify(info, null, 2) }] };
    }
    case "getChildren": {
      const nodeId = args["nodeId"];
      const result = await bridge.call("getChildren", nodeId);
      if (!result) {
        throw new Error(`Node not found: ${nodeId}`);
      }
      return { content: [{ type: "text", text: JSON.stringify(result, null, 2) }] };
    }
    case "getScreenshot": {
      const nodeId = args["nodeId"];
      const scale = args["scale"] ?? 1;
      const screenshotData = await bridge.call("getScreenshot", nodeId, scale);
      if (!screenshotData) {
        throw new Error(`Could not capture screenshot for node: ${nodeId}`);
      }
      const content = [
        { type: "image", data: screenshotData.base64, mimeType: screenshotData.mimeType }
      ];
      if (screenshotData.wasResized) {
        content.push({
          type: "text",
          text: `Note: Image was resized to ${screenshotData.width}x${screenshotData.height}px to fit size limits.`
        });
      }
      return { content };
    }
    case "getJSX": {
      const nodeId = args["nodeId"];
      const format = args["format"] || "tailwind";
      const result = await bridge.call("getJSX", nodeId, format, true);
      if (!result) {
        throw new Error("Editor not ready for JSX generation");
      }
      if ("error" in result) {
        throw new Error(result.error);
      }
      return { content: [{ type: "text", text: result.jsx }] };
    }
    case "getTreeSummary": {
      const nodeId = args["nodeId"];
      const depth = args["depth"];
      const result = await bridge.call("getTreeSummary", nodeId, depth);
      if (!result) {
        throw new Error(`Node not found: ${nodeId}`);
      }
      return { content: [{ type: "text", text: result.summary }] };
    }
    case "findPlacement": {
      const width = args["width"];
      const height = args["height"];
      const result = await bridge.call("findPlacement", width, height);
      if (!result) {
        throw new Error("Editor not ready. Ensure a file is open in Paper.");
      }
      return { content: [{ type: "text", text: JSON.stringify(result) }] };
    }
    case "getComputedStyles": {
      const nodeIds = args["nodeIds"];
      const styles = await bridge.call("getComputedStyles", nodeIds);
      if (!styles) {
        throw new Error("Editor not ready. Ensure a file is open in Paper.");
      }
      return { content: [{ type: "text", text: JSON.stringify(styles, null, 2) }] };
    }
    case "getFillImage": {
      const nodeId = args["nodeId"];
      const imageData = await bridge.call("getFillImage", nodeId);
      if (!imageData) {
        return { content: [{ type: "text", text: "Node does not have an image fill" }] };
      }
      const metadata = {
        originalUrl: imageData.originalUrl,
        mimeType: imageData.mimeType,
        width: imageData.width,
        height: imageData.height
      };
      if (imageData.wasResized) {
        metadata.note = "Image was resized to fit size limits.";
      }
      return {
        content: [
          { type: "image", data: imageData.base64, mimeType: imageData.mimeType },
          { type: "text", text: JSON.stringify(metadata) }
        ]
      };
    }
    default:
      return null;
  }
}

