// src/mcp/index.ts
function initMcpServer(getWindow) {
  const bridge = createBridge(getWindow);
  const { httpServer } = createMcpServer(bridge);
  return {
    cleanup: () => {
      console.log("[mcp-server] Shutting down MCP server...");
      httpServer.close();
    }
  };
}

